def interpret(program):
    if not program or not program.strip():
        return []
    tokens = program.split()
    stack = []

    def execute(toks, pos):
        while pos < len(toks):
            token = toks[pos]

            if token == 'IFPOS':
                if len(stack) < 1:
                    return False
                val = stack.pop()

                depth = 1
                true_start = pos + 1
                else_pos = None
                end_pos = None
                scan = pos + 1
                while scan < len(toks):
                    if toks[scan] == 'IFPOS':
                        depth += 1
                    elif toks[scan] == 'END':
                        depth -= 1
                        if depth == 0:
                            end_pos = scan
                            break
                    elif toks[scan] == 'ELSE' and depth == 1:
                        else_pos = scan
                    scan += 1

                if end_pos is None:
                    return False

                if val >= 0:
                    if else_pos is not None:
                        branch = toks[true_start:else_pos]
                    else:
                        branch = toks[true_start:end_pos]
                    if not execute(branch, 0):
                        return False
                else:
                    if else_pos is not None:
                        branch = toks[else_pos + 1:end_pos]
                        if not execute(branch, 0):
                            return False

                pos = end_pos + 1
                continue

            elif token == 'DUP':
                if len(stack) < 1:
                    return False
                stack.append(stack[-1])
            elif token == 'SWAP':
                if len(stack) < 2:
                    return False
                stack[-1], stack[-2] = stack[-2], stack[-1]
            elif token == 'POP':
                if len(stack) < 1:
                    return False
                stack.pop()
            elif token in ('+', '-', '*', '/'):
                if len(stack) < 2:
                    return False
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    if b == 0:
                        return False
                    result = abs(a) // abs(b)
                    if (a < 0) != (b < 0):
                        result = -result
                    stack.append(result)
            elif token in ('ELSE', 'END'):
                return False
            else:
                try:
                    stack.append(int(token))
                except ValueError:
                    return False

            pos += 1

        return True

    if execute(tokens, 0):
        return stack
    else:
        return "ERROR"

