import unittest

class TestMiniStack(unittest.TestCase):

    # Visible tests
    def test_basic_arithmetic(self):
        self.assertEqual(interpret("3 5 +"), [8])

    def test_dup_and_multiply(self):
        self.assertEqual(interpret("5 DUP *"), [25])

    def test_ifpos_true_branch(self):
        self.assertEqual(interpret("1 IFPOS 10 ELSE 20 END"), [10])

    # Hidden edge-case tests
    def test_hidden_ifpos_false_branch(self):
        self.assertEqual(interpret("-1 IFPOS 10 ELSE 20 END"), [20])

    def test_hidden_ifpos_zero_is_nonneg(self):
        self.assertEqual(interpret("0 IFPOS 10 ELSE 20 END"), [10])

    def test_hidden_nested_ifpos(self):
        self.assertEqual(interpret("5 IFPOS 3 IFPOS 10 ELSE 20 END ELSE 30 END"), [10])

    def test_hidden_deeply_nested(self):
        self.assertEqual(interpret("-1 IFPOS 1 IFPOS 100 END ELSE -1 IFPOS 200 ELSE 300 END END"), [300])

    def test_hidden_division_by_zero(self):
        self.assertEqual(interpret("10 0 /"), "ERROR")

    def test_hidden_stack_underflow(self):
        self.assertEqual(interpret("+"), "ERROR")

    def test_hidden_empty_program(self):
        self.assertEqual(interpret(""), [])

    def test_hidden_swap(self):
        self.assertEqual(interpret("1 2 SWAP"), [2, 1])

    def test_hidden_pop(self):
        self.assertEqual(interpret("1 2 3 POP"), [1, 2])

    def test_hidden_complex_branch(self):
        self.assertEqual(interpret("4 2 SWAP - DUP IFPOS 1 ELSE 0 END"), [-2, 0])

    def test_hidden_ifpos_no_else_false(self):
        self.assertEqual(interpret("-1 IFPOS 10 END"), [])

    def test_hidden_negative_division_truncates_toward_zero(self):
        self.assertEqual(interpret("-7 2 /"), [-3])

    def test_hidden_unmatched_ifpos(self):
        self.assertEqual(interpret("1 IFPOS 2"), "ERROR")

    def test_hidden_stray_end(self):
        self.assertEqual(interpret("1 2 END"), "ERROR")

    def test_hidden_stray_else(self):
        self.assertEqual(interpret("1 ELSE"), "ERROR")

    def test_hidden_unknown_token(self):
        self.assertEqual(interpret("1 FOO"), "ERROR")

    def test_hidden_multi_op_in_branch(self):
        self.assertEqual(interpret("1 IFPOS 3 4 + ELSE 0 END"), [7])

    def test_hidden_dup_on_empty(self):
        self.assertEqual(interpret("DUP"), "ERROR")

    def test_hidden_push_only(self):
        self.assertEqual(interpret("1 2 3"), [1, 2, 3])

if __name__ == '__main__':
    unittest.main()
